// Getters are only allowed inside structs (not enums). The `getter` attribute
// remains deserialize-related outside of Serialize derives and so requires
// remote derive in those cases.
fn check_getter(cx: &Ctxt, cont: &Container, derive: Derive) {
    match cont.data {
        Data::Enum(_) => {
            if cont.data.has_getter() {
                cx.error_spanned_by(
                    cont.original,
                    "#[serde(getter = \"...\")] is not allowed in an enum",
                );
            }
            if cont.data.has_serialize_getter() {
                cx.error_spanned_by(
                    cont.original,
                    "#[serde(serialize_getter = \"...\")] is not allowed in an enum",
                );
            }
        }
        Data::Struct(_, _) => {
            if cont.data.has_getter()
                && cont.attrs.remote().is_none()
                && !matches!(derive, Derive::Serialize)
            {
                cx.error_spanned_by(
                    cont.original,
                    "#[serde(getter = \"...\")] can only be used in structs that have #[serde(remote = \"...\")]",
                );
            }
        }
    }
}

