fn get_member(params: &Parameters, field: &Field, member: &Member) -> TokenStream {
    let self_var = &params.self_var;

    if let Some(getter) = field.attrs.serialize_getter() {
        let ty = field.ty;
        let getter = if getter.qself.is_none()
            && getter.path.leading_colon.is_none()
            && getter.path.segments.len() == 1
            && getter.path.segments[0].arguments.is_none()
        {
            quote!(#self_var.#getter())
        } else {
            quote!(#getter(#self_var))
        };
        return quote!(_serde::__private::ser::constrain::<#ty>(&#getter));
    }

    match (params.is_remote, field.attrs.getter()) {
        (false, None) => {
            if params.is_packed {
                quote!(&{#self_var.#member})
            } else {
                quote!(&#self_var.#member)
            }
        }
        (true, None) => {
            let inner = if params.is_packed {
                quote!(&{#self_var.#member})
            } else {
                quote!(&#self_var.#member)
            };
            let ty = field.ty;
            quote!(_serde::__private::ser::constrain::<#ty>(#inner))
        }
        (_, Some(getter)) => {
            let ty = field.ty;
            quote!(_serde::__private::ser::constrain::<#ty>(&#getter(#self_var)))
        }
    }
}

